// Parse the AI response and extract JSON
const aiResponse = $input.first().json.output || '';

try {
  // Try to find JSON in the response
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    return {
      suggestion: parsed.suggestion || 'Dodaj wiecej danych, zeby Koly mogla lepiej analizowac Twoj biznes.',
      category: parsed.category || 'operations'
    };
  }
} catch (e) {
  // If JSON parsing fails, return the raw text as suggestion
}

// Fallback - return AI response as suggestion
return {
  suggestion: aiResponse || 'Dodaj wiecej danych, zeby Koly mogla lepiej analizowac Twoj biznes.',
  category: 'operations'
};
